import { fetchFromPublicSource } from "../lib/sourcing/publicSourceAdapter"
import { normalizeListing } from "../lib/sourcing/normalizeListing"
import { fingerprint } from "../dedupe/fingerprint"
import { dedupe } from "../dedupe/dedupeListings"
import { evaluateProperty } from "../lib/underwriting/evaluateProperty"
import { exportEvaluations } from "@/exports/exportEvaluations"
import { saveNormalizedListings } from "@/exports/saveNormalizedListings"
import { saveRawPayload } from "@/exports/saveRawPayload"

// Helper function to deep log objects and arrays
function logDeep(label: string, data: any, depth: number = 10) {
  console.log(`\n>>> ${label}:`)
  console.log(JSON.stringify(data, null, 2))
}

export async function run() {
  console.log("PIPELINE STARTED:", new Date().toISOString())

  const raw = await fetchFromPublicSource()
  
  console.log(`\n✓ Fetched ${raw.length} raw records from source\n`)

  const normalizedListings = []
  const evaluatedProperties = []

  for (let i = 0; i < raw.length; i++) {
    const record = raw[i]
    
    console.log(`\n${'='.repeat(80)}`)
    console.log(`PROCESSING RECORD ${i + 1}/${raw.length}`)
    console.log(`${'='.repeat(80)}`)
    
    // Log raw record
    logDeep(`RAW RECORD [ID: ${record.externalId}]`, record)
    
    // Normalize
    const listing = normalizeListing(record)
    
    if (!listing) {
      console.warn(`❌ WARNING: normalizeListing returned undefined for record ID: ${record.externalId}`)
      console.warn("Raw record was:", record)
      continue
    }
    
    logDeep(`NORMALIZED LISTING [ID: ${listing.externalId}]`, listing)
    normalizedListings.push(listing)
    
    // Fingerprint
    const fp = fingerprint(listing)
    logDeep(`FINGERPRINT [ID: ${listing.externalId}]`, {
      fingerprint: fp,
      address: listing.address,
      city: listing.city,
      price: listing.price,
    })

    // Dedupe
    const result = dedupe(listing, fp)
    console.log(`\n📊 DEDUPE RESULT: ${result}`)
    
    if (result === "UNCHANGED") {
      console.log("→ Skipping unchanged listing")
      continue
    }

    // Evaluate
    const evaluation = evaluateProperty(listing)
    
    logDeep(`EVALUATION [ID: ${listing.externalId}]`, evaluation)
    
    // Log evaluation details with full expansion
    if (evaluation) {
      console.log("\n📋 EVALUATION DETAILS:")
      console.log("  externalId:", evaluation.externalId)
      console.log("  address:", evaluation.address)
      console.log("  evaluatedAt:", evaluation.evaluatedAt)
      
      if (evaluation.underwriting) {
        console.log("  underwriting:")
        console.log("    status:", evaluation.underwriting.status)
        
        if (evaluation.underwriting.arv) {
          logDeep("    ARV (After Repair Value)", evaluation.underwriting.arv)
        }
        
        if (evaluation.underwriting.costs) {
          logDeep("    COSTS", evaluation.underwriting.costs)
        }
        
        if (evaluation.underwriting.profit) {
          logDeep("    PROFIT", evaluation.underwriting.profit)
        }
        
        if (Array.isArray(evaluation.underwriting.failureReasons)) {
          logDeep("    FAILURE REASONS", evaluation.underwriting.failureReasons)
        }
      }
    }
    
    evaluatedProperties.push(evaluation)
    exportEvaluations([evaluation])
  }
  
  console.log(`\n${'='.repeat(80)}`)
  console.log(`PIPELINE SUMMARY`)
  console.log(`${'='.repeat(80)}`)
  
  console.log(`\n📦 RAW RECORDS: ${raw.length}`)
  logDeep("Raw records count by city", 
    raw.reduce((acc: any, r: any) => {
      acc[r.city] = (acc[r.city] || 0) + 1
      return acc
    }, {})
  )
  
  console.log(`\n✓ NORMALIZED LISTINGS: ${normalizedListings.length}`)
  logDeep("Normalized listings", normalizedListings.slice(0, 3), 1) // First 3 only
  
  console.log(`\n✓ EVALUATED PROPERTIES: ${evaluatedProperties.length}`)
  evaluatedProperties.forEach((eva, idx) => {
    console.log(`\n  [${idx + 1}] ${eva.address || 'Unknown'} - Status: ${eva.underwriting?.status || 'N/A'}`)
  })
  
  console.log(`\n💾 SAVING ${normalizedListings.length} NORMALIZED LISTINGS`)
  saveNormalizedListings(normalizedListings)
  
  console.log(`💾 SAVING ${raw.length} RAW RECORDS`)
  saveRawPayload(raw)

  console.log(`\n✅ PIPELINE COMPLETED: ${new Date().toISOString()}\n`)
}