import fs from "fs"
import path from "path"
import { PublicListing } from "../lib/sourcing/normalizeListing"

export function saveNormalizedListings(listings: PublicListing[]) {
  const filePath = path.join(
    process.cwd(),
    "data",
    "normalized-listings.json"
  )

  fs.writeFileSync(
    filePath,
    JSON.stringify(
      {
        runAt: new Date().toISOString(),
        count: listings.length,
        listings,
      },
      null,
      2
    )
  )
}
